  1	import React, { FC, useEffect, useMemo } from 'react';
  2	import { useImmer } from 'use-immer';
  3	
  4	import { V1VirtualMachine } from '@kubevirt-ui/kubevirt-api/kubevirt';
  5	import { useKubevirtTranslation } from '@kubevirt-utils/hooks/useKubevirtTranslation';
  6	import { getNamespace } from '@kubevirt-utils/resources/shared';
  7	import { isEmpty } from '@kubevirt-utils/utils/utils';
  8	import { Button, Form } from '@patternfly/react-core';
  9	import { PlusCircleIcon } from '@patternfly/react-icons';
 10	
 11	import EnvironmentEditor from './components/EnvironmentEditor';
 12	import EnvironmentFormActions from './components/EnvironmentFormActions';
 13	import EnvironmentFormSkeleton from './components/EnvironmentFormSkeleton';
 14	import EnvironmentFormTitle from './components/EnvironmentFormTitle';
 15	import useEnvironments from './hooks/useEnvironments';
 16	
 17	import './EnvironmentForm.scss';
 18	
 19	type EnvironmentFormProps = {
 20	  onEditChange?: (edited: boolean) => void;
 21	  updateVM: (updatedVM: V1VirtualMachine) => Promise<V1VirtualMachine | void>;
 22	  vm: V1VirtualMachine;
 23	};
 24	
 25	const EnvironmentForm: FC<EnvironmentFormProps> = ({ onEditChange, updateVM, vm }) => {
 26	  const [temporaryVM, setTemporaryVM] = useImmer(vm);
 27	
 28	  const { t } = useKubevirtTranslation();
 29	
 30	  const {
 31	    edited,
 32	    environments,
 33	    error: formError,
 34	    onEnvironmentAdd,
 35	    onEnvironmentChange,
 36	    onEnvironmentRemove,
 37	    setError: setFormError,
 38	  } = useEnvironments(temporaryVM, vm, setTemporaryVM, onEditChange);
 39	
 40	  useEffect(() => {
 41	    setTemporaryVM(vm);
 42	    setFormError(null);
 43	  }, [setFormError, setTemporaryVM, vm]);
 44	
 45	  const environmentNamesSelected = useMemo(
 46	    () => environments.map((env) => env.name),
 47	    [environments],
 48	  );
 49	
 50	  if (isEmpty(vm)) return <EnvironmentFormSkeleton />;
 51	
 52	  return (
 53	    <>
 54	      <EnvironmentFormTitle />
 55	      <Form className="environment-form__form">
 56	        {environments.length !== 0 && (
 57	          <div className="row pairs-list__heading">
 58	            <div className="col-xs-5 text-secondary text-uppercase" id="environment-name-header">
 59	              {t('config map / secret / service account')}
 60	            </div>
 61	            <div className="col-xs-5 text-secondary text-uppercase" id="environment-serial-header">
 62	              {t('Serial Number')}
 63	            </div>
 64	            <div className="col-xs-1 co-empty__header" />
 65	          </div>
 66	        )}
 67	
 68	        {environments.map((environment, index) => (
 69	          <EnvironmentEditor
 70	            diskName={environment.diskName}
 71	            environmentName={environment.name}
 72	            environmentNamesSelected={environmentNamesSelected}
 73	            id={index}
 74	            key={environment.name}
 75	            kind={environment.kind}
 76	            namespace={getNamespace(vm)}
 77	            onChange={onEnvironmentChange}
 78	            onRemove={onEnvironmentRemove}
 79	            serial={environment?.serial}
 80	          />
 81	        ))}
 82	
 83	        <div className="row">
 84	          <div className="col-xs-12">
 85	            <Button
 86	              className="pf-m-link--align-left"
 87	              onClick={onEnvironmentAdd}
 88	              type="button"
 89	              variant="link"
 90	            >
 91	              <PlusCircleIcon /> {t('Add Config Map, Secret or Service Account')}
 92	            </Button>
 93	          </div>
 94	        </div>
 95	
 96	        <EnvironmentFormActions
 97	          onReload={() =>
 98	            setTemporaryVM((draftVM) => {
 99	              draftVM.spec = vm.spec;
100	            })
101	          }
102	          closeError={() => setFormError(null)}
103	          error={formError}
104	          isSaveDisabled={!edited || !environments.every((env) => env.name)}
105	          onSave={() => updateVM(temporaryVM)}
106	        />
107	      </Form>
108	    </>
109	  );
110	};
111	
112	export default EnvironmentForm;

